const METH_TABLES_FR = {"Hea03": [{"title": "Tableau 16 : DER mélanopique typique pour les types courants d\'éclairage électrique","after_section": "M1.4.2","headers": ["Type d\'éclairage électrique","DER mélanopique typique"],"rows": [["LED, blanc chaud, TCC 2700K","0.42"],["LED, blanc chaud, TCC 3000K","0.47"],["LED, blanc neutre, TCC 4100K","0.63"],["LED, blanc froid, TCC 5700K","0.72"],["Éclairage fluorescent, blanc chaud, TCC 3000K","0.40"],["Éclairage fluorescent, blanc neutre, TCC 4000K","0.56"],["Éclairage fluorescent, blanc froid, TCC 5000K","0.68"],["Éclairage à incandescence","0.50"],["Notes :\n1. La température de couleur corrélée (TCC) doit correspondre aux fiches techniques du produit ou être mesurée in situ à l\'aide d\'un spectromètre.\n2. Lorsque la TCC mesurée diffère des valeurs indiquées ci-dessus, le DER mélanopique correspondant à la TCC la plus proche peut être utilisé. Pour une plus grande précision, le DER mélanopique peut être déterminé par interpolation ou extrapolation.\n3. S\'il existe d\'autres types d\'éclairage électrique non répertoriés ci-dessus, la valeur TCC doit être déterminée et les valeurs correspondantes pour l\'éclairage fluorescent doivent être utilisées.",""]]}],"Hea04": [{"title": "Tableau 19 : Teneur maximale en COV pour les peintures et revêtements","after_section": "M2.3","headers": ["Catégorie de produit","Teneur en COV du produit\nprêt à l\'emploi (g/l)","Exigences d\'essai"],"rows": [["Murs et plafonds intérieurs mats (Brillance <25@60°)","10","ISO 11890-2\nou\nISO 17895\nou\nCalcul basé sur les\ningrédients et les matières\npremières"],["Murs et plafonds intérieurs brillants (Brillance >25@60°)","40",""],["Peintures de finition et de revêtement intérieures pour bois et métal","90",""],["Vernis de finition intérieurs et lasures pour bois, y compris les lasures opaques","65",""],["Lasures pour bois intérieures à couche mince","50",""],["Primaires d\'accrochage","15",""],["Primaires fixateurs","15",""],["Revêtements haute performance monocomposants","100",""],["Revêtements haute performance bicomposants réactifs pour usages spécifiques tels que les sols","80",""],["Revêtements multicolores","80",""],["Revêtements à effets décoratifs","80",""]]}],"Hea05": [{"title": "Tableau 47 : Heures d\'exploitation par défaut par type de bâtiment pour une journée type","after_section": "M1.1","headers": ["Type de bâtiment","Heures d\'exploitation type",""],"rows": [["Enseignement : Maternelle, école, lycée","07:30–10:00, 15:00–17:30",""],["Enseignement : Établissements d\'enseignement supérieur","08:00–19:00",""],["Santé","07:00–20:00 (comprenant les heures de visite et les horaires de jour classiques)",""],["Commerce : Centre commercial","09:00–19:00",""],["Commerce : Supermarché","08:00–22:00",""],["Commerce : Services de vente","08:00–18:00",""],["Commerce : Supérette","07:00–22:00",""],["Commerce : Zone commerciale ou entrepôt","08:00–20:00",""],["Commerce : Magasin de détail","08:30–17:30",""],["Résidentiel","08:00–19:00",""],["Services publics : Tribunal","08:00–19:00",""],["Autre","08:00–19:00",""],["","Ou utiliser l\'une des plages horaires ci-dessus, selon le type de bâtiment.",""],["Bâtiment ouvert 24h/24","07:00–20:00",""]]}],"Hea06": [{"title": "Tableau 25 : Composition de l\'ensemble de test","after_section": "M2.1","headers": ["Type de groupe","Essais aériens –\nmurs séparatifs","Essais aériens –\nplanchers séparatifs","Essais d\'impact –\nplanchers séparatifs","Total"],"rows": [["Logements avec murs séparatifs\nuniquement.\nEx. maisons ou pavillons de plain-pied","2","0","0","2"],["Logements avec murs séparatifs\net planchers.\nEx. appartements","2","2","2","6"]]}],"Ene03": [{"title": "Tableau 29 : Exemples de zones fonctionnelles pertinentes pour différents types de bâtiments","after_section": "M3.2","headers": ["Type de bâtiment","Zones fonctionnelles pertinentes"],"rows": [["Établissement résidentiel (séjour\nde longue durée)","1. Unité résidentielle\n2. Parties communes"],["Bureau","1. Zones de bureaux, généralement par étage (ou regroupement similaire pertinent)\n2. Parties communes\n3. Restauration"],["Commerce","1. Surface de vente\n2. Stockage et entrepôt\n3. Chambre froide\n4. Bureaux\n5. Restauration\n6. Cellules locataires"],["Industriel","1. Zones de bureaux\n2. Zone d\'exploitation\n3. Zones annexes (ex. cantines)"],["Hôtels","1. Zones de bureaux\n2. Restauration (ex. cuisine, restaurant)\n3. Salles de conférence\n4. Piscine ou installations de loisirs\n5. Chambres, par étage ou noyau (ou regroupement similaire pertinent)"],["Enseignement","1. Cuisines (hors petites cuisines du personnel et salles de technologie alimentaire)\n2. Ateliers\n3. Salles de classe\n4. Amphithéâtres\n5. Salles de conférence\n6. Piscines\n7. Gymnases\n8. Zones de process\n9. Laboratoires\n10. Salles serveurs informatiques\n\nNote : Le sous-comptage individuel des salles de classe standard ou des salles de séminaire n\'est pas requis."],["Hôpitaux et autres établissements de santé","1. Installations de physique médicale\n2. Rééducation incluant les bassins de balnéothérapie\n3. Services de stérilisation centrale (ou équivalent)\n4. Zones équipées de matériel spécialisé (ex. cuisines et blanchisseries de taille professionnelle)\n5. Salles serveurs informatiques\n6. Services de pharmacie\n7. Laboratoires\n8. Zones louées (ex. restauration, commerce, blanchisserie)\n\nNote : Des sous-compteurs peuvent être installés par plateau dans les petits bâtiments de santé (surface utile brute < 1000 m²) ne comportant pas de zones fonctionnelles à forte charge énergétique."],["Autre","Les autres types de bâtiments à occupation unique peuvent utiliser les zones fonctionnelles ci-dessus comme guide pour les types de zones pouvant nécessiter un sous-comptage."]]}],"Ene05": [{"title": "Tableau 31 : Exigences réputées conformes pour les labels et référencements d\'efficacité énergétique","after_section": "M4.2","headers": ["Équipement","Label ou référencement","Exigence"],"rows": [["Tous types d\'équipements","ENERGY STAR® (Agence américaine de protection de l\'environnement)(1)","Certifié"],["","Energy Technology List (Gouvernement britannique)(2)","Référencé"],["Réfrigérateurs","Étiquetage énergétique UE (mars 2021)(3)","E ou supérieur"],["","Étiquette énergie (Gouvernement australien)(4)","3,5 étoiles ou plus"],["Réfrigérateurs-congélateurs","Étiquetage énergétique UE (mars 2021)","E ou supérieur"],["Congélateurs","Étiquetage énergétique UE (mars 2021)","Classe D ou supérieure"],["","Étiquette énergie (Gouvernement australien)","3,5 étoiles ou plus"],["Lave-linge","Étiquetage énergétique UE (mars 2021)","Classe B ou supérieure"],["","Étiquette énergie (Gouvernement australien)","4 étoiles ou plus"],["Lave-linge séchants","Étiquetage énergétique UE (mars 2021)","Classe D ou supérieure"],["Sèche-linge","Étiquetage énergétique UE (mars 2021)","Classe D ou supérieure"],["Climatiseurs individuels","Étiquetage énergétique UE (original)","B ou supérieur"],["Écrans d\'ordinateur","Étiquetage énergétique UE (mars 2021)","Classe D ou supérieure"],["","Étiquette énergie (Gouvernement australien)","6 étoiles ou plus"],["Lave-vaisselle","Étiquetage énergétique UE (mars 2021)","Classe C ou supérieure"],["","Étiquette énergie (Gouvernement australien)","3,5 étoiles ou plus"],["Téléviseurs","Étiquetage énergétique UE (mars 2021)","Classe E ou supérieure"],["","Étiquette énergie (Gouvernement australien)","5 étoiles ou plus"]]}],"Ene06": [{"title": "Tableau 33 : Exigences réputées conformes pour les systèmes d\'éclairage extérieur","after_section": "M4.2.1","headers": ["Réf","Exigences pour les systèmes d\'éclairage extérieur"],"rows": [["1","L\'efficacité lumineuse initiale moyenne de l\'ensemble des systèmes d\'éclairage extérieur concernés dans la zone de construction\natteint ≥ 70 lumens par watt de circuit."],["2","Tous les luminaires extérieurs sont commandés automatiquement pour empêcher leur fonctionnement pendant les heures de jour et sont équipés\nde détecteurs de présence dans les zones de circulation piétonne intermittente."]]},{"title": "Tableau 34 : Exigences réputées conformes pour les systèmes de stockage frigorifique","after_section": "M4.2.2.2","headers": ["Réf","Exigences pour les systèmes de stockage frigorifique"],"rows": [["1","Composants économes en énergie\nLorsque les composants suivants sont inclus, ils doivent satisfaire aux exigences de labels ou référencements indépendants externes :\n1. Groupes de condensation à air\n2. Système de refroidissement de cave\n3. Condenseurs évaporatifs\n4. Groupes refroidisseurs monoblocs\n5. Compresseurs frigorifiques\n6. Régulations de systèmes frigorifiques.\nNote : La liste des technologies énergétiques définit les critères d\'efficacité énergétique pour ces composants\n(etl.energysecurity.gov.uk/products/refrigeration-equipment)."],["2","Conçu pour minimiser les déperditions thermiques\nDémontrer les éléments suivants :\n— Niveaux d\'isolation élevés\n— Infiltrations d\'air réduites"],["3","Régulations pour optimiser la gestion de la température, de l\'humidité et du débit d\'air\nCela peut être réalisé en installant des régulations automatiques centrales incluant des contrôles anti-sabotage, des commandes\nd\'éclairage automatiques, une température de consigne fixe et des bandes mortes de température."],["4","Le système fera l\'objet d\'une mise en service et d\'essais\nLe système frigorifique a été mis en service conformément au critère 7 de Man 04 Mise en service et réception. Cela ne nécessite pas l\'obtention du crédit « Mise en service ».\n\nNote : La documentation des procédures d\'essais et de mise en service relatives à l\'installation, telles que les essais de pression, les essais d\'étanchéité et la validation de conformité au cahier des charges, doit être fournie."]]},{"title": "Tableau 35 : Exigences réputées conformes pour les ascenseurs et escaliers mécaniques","after_section": "M4.2.3.2","headers": ["Réf","Exigences pour les ascenseurs et escaliers mécaniques"],"rows": [["1","Le nombre et la taille des ascenseurs, escaliers mécaniques ou trottoirs roulants nécessaires pour répondre à la demande\nde transport prévue et aux schémas d\'utilisation ont été déterminés et minimisés."],["2a","Pour les ascenseurs, la consommation énergétique d\'un système standard et du système réel a été estimée\nconformément à l\'ISO 25745 Performance énergétique des ascenseurs, escaliers mécaniques et trottoirs roulants :\nPartie 2 : Calcul et classification énergétique des ascenseurs"],["2b","Pour les escaliers mécaniques et les trottoirs roulants, la consommation énergétique d\'un système standard et du système réel\na été estimée conformément à l\'ISO 25745 Performance énergétique des ascenseurs, escaliers mécaniques et trottoirs roulants :\nPartie 3 : Calcul et classification énergétique des escaliers mécaniques et trottoirs roulants."],["3a","Les ascenseurs ont atteint la classe d\'efficacité énergétique A selon l\'ISO 25745.\nOU\nLes mesures suivantes sont intégrées aux ascenseurs le cas échéant :\n1. Variateurs à récupération d\'énergie.\n2. Les ascenseurs se mettent en veille après une période d\'inactivité définie.\n3. L\'éclairage de cabine, l\'affichage numérique et les écrans électroniques ont une efficacité ≥ 70 lumens par watt de circuit.\n4. Contrôleurs de variateur capables d\'une régulation en vitesse, tension et fréquence variables (VVVF) du moteur d\'entraînement, ou autre type de variateur offrant une efficacité énergétique optimale équivalente."],["3b","Les escaliers mécaniques ou trottoirs roulants ont atteint la classe d\'efficacité énergétique A+++ selon l\'ISO 25745.\nOU\nLes mesures suivantes sont intégrées aux escaliers mécaniques ou trottoirs roulants le cas échéant :\n1. Capteurs de charge synchronisant la puissance du moteur à la demande des usagers via un variateur de vitesse, avec un onduleur fonctionnant en permanence pour moduler la puissance en fonction de la demande. OU\n2. Capteurs de présence pour un fonctionnement automatisé (marche automatique), afin que l\'escalier mécanique se mette en veille en l\'absence de demande."],["4","Lors du suivi de la route « mesures » pour 3a ou 3b, un membre dûment qualifié de l\'équipe de projet doit confirmer que les mesures ont été incluses dans le cahier des charges ou justifier pourquoi elles ne sont pas applicables. Par exemple, parce qu\'il n\'est pas techniquement réalisable, ou parce que le coût supplémentaire ou l\'impact sur le carbone biogénique est peu susceptible d\'être rentabilisé au cours de la durée de vie du système."]]},{"title": "Tableau 36 : Exigences réputées conformes pour les piscines","after_section": "M4.2.4","headers": ["Réf",""],"rows": [["Réf ","Exigences pour les piscines"],["1","Les pompes de piscine doivent être équipées de variateurs de vitesse."],["2","Les systèmes de chauffage de piscine doivent être économes en énergie, par exemple en utilisant des pompes à chaleur ou la chaleur provenant de sources d\'énergie renouvelable sur site."],["3","Des couvertures de piscine automatiques ou semi-automatiques, ou des couvertures « liquides » avec un système de dosage automatique, sont installées sur toute la surface de TOUTES les piscines, y compris les spas et jacuzzis (le cas échéant)."],["4","La température de l\'air dans le hall de piscine peut être régulée pour être supérieure de 1°C à la température de l\'eau."]]},{"title": "Tableau 37 : Exigences réputées conformes pour les blanchisseries industrielles","after_section": "M4.2.5","headers": ["Réf","Exigences pour les blanchisseries industrielles"],"rows": [["1","La récupération de chaleur sur les eaux usées est installée sur tous les équipements."],["2","Les eaux grises sont utilisées pour une partie du processus de lavage. Elles peuvent être recyclées à partir du rinçage final et réutilisées\npour le prélavage suivant."]]},{"title": "Tableau 38 : Exigences réputées conformes pour les systèmes de refroidissement des salles serveurs","after_section": "M4.2.6","headers": ["Réf","Exigences pour les systèmes de refroidissement des salles serveurs"],"rows": [["Le refroidissement est assuré par ventilation naturelle ou mécanique.\n\nLe refroidissement actif ne peut être utilisé que lorsque le refroidissement de la température interne dans les salles serveurs est conçu pour répondre aux conditions de fonctionnement les plus larges autorisées, telles que définies par les classes de température ASHRAE (ou équivalent local/national), afin de minimiser les charges de refroidissement.\n\nCes conditions de fonctionnement doivent tenir compte du type de serveurs qui seront installés et de leur mode de fonctionnement.\n\nUn spécialiste dûment qualifié justifie les conditions de fonctionnement les plus appropriées."," Cooling is provided by natural or forced ventilation.\n\nActive cooling may only be used when the internal temperature cooling in server rooms is designed to meet the \nwidest allowable operating conditions as defined in the ASHRAE temperature classes (or local / national equivalent) to minimise cooling loads.\n\nThese operating conditions must consider the type of servers which will be installed, and how they will be operated.\n\nA suitably qualified specialist justifies the operating conditions which are the most suitable."],["2","Un mécanisme permet l\'arrêt automatique des systèmes lorsqu\'ils ne sont pas utilisés, y compris pendant la nuit."]]}],"Ene07": [{"title": "Tableau 40 : Nombre de crédits disponibles","after_section": "M1","headers": ["Nombre de points de réponse à la demande flexible disponibles","Nombre de crédits disponibles"],"rows": [["0","0"],["1–3","1"],["> 3","2"]]},{"title": "Tableau 41 : Points de réponse à la demande flexible — points disponibles et attribués","after_section": "M1","headers": ["Systèmes présents","Points\ndisponibles","Capacité de réponse flexible à la demande","Points\nattribués"],"rows": [["Chauffage électrique des locaux","1","Le fonctionnement peut être optimisé en fonction des signaux du\nfournisseur d\'électricité ou des sources renouvelables locales.","1"],["Refroidissement électrique des locaux","1","Le fonctionnement peut être optimisé en fonction des signaux du\nfournisseur d\'électricité ou des sources renouvelables locales.","1"],["Eau chaude sanitaire électrique","1","Le fonctionnement peut être optimisé en fonction des signaux du\nfournisseur d\'électricité ou des sources renouvelables locales.","1"],["Points de recharge\nde véhicules électriques","2","Recharge avec contrôle unidirectionnel basé sur les signaux du\nfournisseur d\'électricité ou des sources renouvelables locales.","1"],["","","Recharge avec contrôle bidirectionnel basé sur les signaux du\nfournisseur d\'électricité ou des sources renouvelables locales.","2"],["Autres systèmes ou équipements\navec capacité de réponse\nflexible à la demande","3","Présent","1"],["","","Le système de stockage d\'énergie par batterie est capable de se charger\nen fonction des signaux du fournisseur d\'électricité ou des sources\nrenouvelables locales.","1"],["","","Le système de stockage d\'énergie par batterie est capable de réinjecter\nde l\'électricité dans le réseau.","1"]]}],"Ene08": [{"title": "Tableau 43 : Contrôles installés (chauffage) – points disponibles et attribués","after_section": "M1","headers": ["Système de bâtiment","Type de système","Points\ndisponibles","Type de régulation","Fonctionnalité de régulation","Points\nattribués"],"rows": [["Chauffage","Tous","4","Émission de chaleur au niveau de la pièce – tous générateurs de chaleur","Émission de chaleur régulée au niveau de la pièce/zone","1"],["","","","","Émission de chaleur régulée au niveau de la pièce/zone avec communication entre les régulateurs de pièce et le système de gestion du bâtiment et/ou détection de présence","2"],["","","","ET","",""],["","","","Puissance du générateur de chaleur – pompes à chaleur","Régulation variable (ex. bypass de gaz chaud, régulation de fréquence par onduleur)","1"],["","","","","Régulation variable (ex. bypass de gaz chaud, régulation de fréquence par onduleur)","2"],["","","","OU","",""],["","","","Puissance du générateur de chaleur – autres types de générateurs","Sonde de température extérieure","1"],["","","","","Charge, par exemple consigne de température d\'eau de départ","2"],["","Systèmes avec un fluide de distribution de chaleur (ex. air ou eau)","3","Température de distribution de chaleur","Sonde de température extérieure","1"],["","","","","Sonde de température intérieure","2"],["","","","Régulation à vitesse variable des pompes et/ou ventilateurs","Présent","1"],["","Systèmes avec plusieurs générateurs de chaleur","2","Séquencement des générateurs de chaleur","Les générateurs fonctionnent selon un ordre de priorité fixe","1"],["","","","","Les générateurs fonctionnent selon un ordre de priorité dynamique","2"]]},{"title": "Tableau 44 : Contrôles installés (refroidissement) – points disponibles et attribués","after_section": "M1","headers": ["Système de bâtiment","Type de système","Points\ndisponibles","Type de régulation","Fonctionnalité de régulation","Points\nattribués"],"rows": [["Refroidissement","Tous","2","Émission de froid au niveau de la pièce","Émission de froid régulée au niveau de la pièce/zone","1"],["","","","","Émission de froid régulée au niveau de la pièce/zone avec communication entre les régulateurs de pièce et le système de gestion du bâtiment et/ou détection de présence","2"],["","","2","Puissance du groupe froid","Régulation multi-étages (ex. plusieurs compresseurs tout-ou-rien)","1"],["","","","","Régulation variable (ex. bypass de gaz chaud, régulation de fréquence par onduleur)","2"],["","Systèmes avec un fluide de distribution de froid (ex. air ou eau)","3","Température de distribution de froid","Sonde de température extérieure","1"],["","","","","Sonde de demande de refroidissement","2"],["","","","Régulation à vitesse variable des pompes et/ou ventilateurs","Présent","1"],["","Systèmes avec plusieurs groupes de production","2","Séquencement des groupes froids","Ordre de priorité fixe","1"],["","","","","Ordre de priorité dynamique","2"],["","Systèmes assurant à la fois le chauffage et le refroidissement","2","Contrôles de verrouillage","Verrouillage partiel","1"],["","","","","Verrouillage total","2"]]},{"title": "Tableau 45 : Contrôles installés (ventilation mécanique) – points disponibles et attribués","after_section": "M1","headers": ["Système de bâtiment","Type de système","Points\ndisponibles","Type de régulation","Fonctionnalité de régulation","Points\nattribués"],"rows": [["Ventilation mécanique","Tous","5","Régulation de la ventilation au niveau de la pièce","Débit d\'air régulé par détection de présence","1"],["","","","","Débit d\'air régulé centralement par des sondes de qualité de l\'air","2"],["","","","","Régulation locale du débit d\'air par des sondes de qualité de l\'air","3"],["","","","Régulation de la puissance de la centrale de traitement d\'air","Régulateur multi-étages","1"],["","","","","Régulation automatique du débit ou de la pression en fonction de la demande de débit d\'air de toutes les pièces raccordées","2"],["","Systèmes dans les bâtiments avec chauffage","2","Récupération de chaleur","Récupération de chaleur régulée par des sondes dans l\'air extrait","1"],["","","","","Récupération de chaleur régulée par plusieurs sondes de température ambiante ou régulation prédictive","2"],["","Systèmes dans les bâtiments avec refroidissement","2","Rafraîchissement gratuit (free cooling)","Débits d\'air toujours modulés pour minimiser le refroidissement mécanique","1"],["","","","","Débit d\'air modulé pour minimiser le refroidissement mécanique en fonction de la température et de l\'humidité","2"]]}],"Tra01": [{"title": "Tableau 46 : Équipements et services de proximité","after_section": "M1","headers": ["Type d\'équipement de proximité"],"rows": [["Point de restauration adapté"],["Accès à un distributeur automatique de billets (DAB)"],["Accès à un espace extérieur ouvert adapté"],["Accès à une installation de loisirs ou de sport"],["Bureau de poste accessible au public"],["Équipement collectif / salle communale"],["Pharmacie"],["Cabinet médical ou centre de santé"],["Structure d\'accueil pour enfants ou école"]]},{"title": "Tableau 47 : Heures d\'exploitation par défaut par type de bâtiment pour une journée type","after_section": "M2.2","headers": ["Type de bâtiment","Heures d\'exploitation type",""],"rows": [["Enseignement : Maternelle, école, lycée","07:30–10:00, 15:00–17:30",""],["Enseignement : Établissements d\'enseignement supérieur","08:00–19:00",""],["Santé","07:00–20:00 (comprenant les heures de visite et les horaires de jour classiques)",""],["Commerce : Centre commercial","09:00–19:00",""],["Commerce : Supermarché","08:00–22:00",""],["Commerce : Services de vente","08:00–18:00",""],["Commerce : Supérette","07:00–22:00",""],["Commerce : Zone commerciale ou entrepôt","08:00–20:00",""],["Commerce : Magasin de détail","08:30–17:30",""],["Résidentiel","08:00–19:00",""],["Services publics : Tribunal","08:00–19:00",""],["Autre","08:00–19:00",""],["","Ou utiliser l\'une des plages horaires ci-dessus, selon le type de bâtiment.",""],["Bâtiment ouvert 24h/24","07:00–20:00",""]]}],"Tra02a": [{"title": "Tableau 50 : Score d\'équipement pour l\'infrastructure de recharge VE","after_section": "M1","headers": ["Type d\'infrastructure de recharge VE","Score d\'équipement"],"rows": [["Infrastructure de recharge VE active (≥ 7 kW)","0.5"],["Infrastructure de recharge VE active (≥ 22 kW)","1"],["Infrastructure de recharge VE passive","0.5"]]},{"title": "Tableau 53 : Emplacements vélos requis par type de bâtiment (Option 7)","after_section": "M2","headers": ["Type de bâtiment","Nombre\nd\'emplacements","Unité de\nmesure","Notes"],"rows": [["Type de bâtiment","Nombre\nd\'emplacements","Unité de\nmesure","Notes"],["Type A","1 pour","10 employés","Bâtiment principalement occupé par du personnel ou des employés\navec des visiteurs professionnels occasionnels, ex. bureau,\nindustriel, caserne de pompiers, commissariat. Cela inclut l\'hôtellerie,\noù les visiteurs séjournent généralement moins d\'un mois."],["Type B","1 pour","10 usagers du\nbâtiment (personnel\net visiteurs)","Bâtiment occupé par du personnel permanent avec des visiteurs\nou usagers régulièrement fréquents (résidents ou non).\nCela inclut les cafés, restaurants, lieux culturels et de\ndivertissement, sport et loisirs et hébergements sécurisés.\nLes équipements cyclistes conformes sont requis\nuniquement pour le personnel."],["Types de bâtiments spécifiques","","",""],["Commerce","","",""],["Grand commerce","1 pour","10 employés et","Pour le calcul du personnel, utiliser le nombre maximal d\'employés présents simultanément ou par poste.\nPrévoir un minimum de 10 emplacements vélos pour les usagers du bâtiment."],["","1 pour","20 places de\nstationnement\npublic",""],["Petit commerce","4","Au total","Les emplacements sont accessibles au public à proximité de l\'entrée principale du bâtiment. Les équipements cyclistes conformes sont requis uniquement pour le personnel."],["Enseignement","","",""],["Lorsqu\'un établissement d\'enseignement se compose de bâtiments relevant de plus d\'une catégorie (par exemple, une maternelle et une école primaire), sélectionnez le type de bâtiment dominant dans la Plateforme BREEAM. Calculez l\'exigence séparément pour chaque groupe d\'utilisateurs et combinlez les résultats.\nPar exemple, une école maternelle et primaire combinée devra satisfaire à la fois aux exigences de 1 emplacement pour 10 employés et de 5 emplacements pour les classes du groupe d\'âge.","","",""],["Maternelle","1 pour","10 employés","-"],["École primaire","5 per","Classe du plus grand niveau","Lorsque le nombre de classes varie selon les groupes d\'âge. Par exemple, une école primaire avec cinq classes dans son plus grand groupe d\'âge fournira 25 emplacements de stockage de vélos pour l\'ensemble de l\'école."],["Enseignement secondaire ou supérieur","1 pour","10 employés et","L\'enseignement secondaire couvre l\'éducation des enfants de 11 à 18 ans. Enseignement supérieur : tous les étudiants comptabilisés :\n— Étudiants de premier cycle — Étudiants de deuxième cycle — Doctorants — Post-doctorats"],["","1 pour","10 étudiants",""],["Santé","","",""],["Tous types de bâtiments de santé","1 pour","10 lits ou","Utilisez la plus grande unité de mesure pour le type de bâtiment. Par exemple : — Utilisez les lits pour un hôpital. — Utilisez les cabinets de consultation pour un cabinet de médecin. — Utilisez le personnel lorsqu\'il s\'agit de la plus grande unité de mesure, en fonction du nombre maximal à tout moment ou par poste."],["","1 pour","2 cabinets de consultation ou",""],["","1 pour","10 employés",""],["Établissement résidentiel","","",""],["Résidences étudiantes (cités universitaires), logements pour travailleurs clés, casernes militaires, hébergements résidentiels sécurisés des collectivités locales","1 pour","10 employés et","-"],["","1 pour","2 résidents",""],["Maison de retraite, logement protégé","1 pour","10 employés et","-"],["","1 pour","10 visiteurs ou lits",""],["Échelle progressive de conformité\nLorsque le nombre d\'utilisateurs du bâtiment (basé sur l\'unité de mesure) dépasse 200, l\'échelle progressive de conformité peut être utilisée pour identifier le nombre approprié d\'emplacements vélos requis (voir M2.5).","","",""]]},{"title": "Tableau 54 : Distance en zone rurale pour réduction du nombre d\'emplacements vélos","after_section": "M2.4","headers": ["Distance au lieu urbain le plus proche","Ajustement des emplacements vélos et équipements cyclistes"],"rows": [["> 15 km","Réduit de 50 %"],["> 30 km","Réduit de 70 %"],["> 50 km","Réduit de 90 %"]]},{"title": "Tableau 55 : Échelle de conformité progressive – multiplicateur selon le nombre d\'utilisateurs","after_section": "M2.5","headers": ["Nombre d\'utilisateurs","Multiplicateur pour l\'unité de mesure standard"],"rows": [["1 à 200 utilisateurs","× 1,0"],["201 à 300 utilisateurs","× 1,5"],["301 à 400 utilisateurs","× 2,0"],["401+ utilisateurs","× 2,5"]]}],"Tra02b": [{"title": "Tableau 59 : Infrastructure de recharge VE et nombre de points disponibles","after_section": "M1","headers": ["Infrastructure de recharge VE","Points"],"rows": [["Infrastructure de recharge VE","Points"],["Toutes les places de stationnement doivent être équipées d\'une infrastructure de recharge VE passive, telle que des\ncheminements de câbles et une capacité d\'alimentation électrique pour supporter l\'installation future de bornes de recharge VE.","1"],["Chaque nouveau logement doit avoir accès à au moins un emplacement de recharge VE actif — Stationnement individuel :\n(minimum 7 kW). Toutes les places de stationnement restantes doivent disposer d\'une infrastructure de recharge VE passive.","2"],["Au moins 20 % des places de stationnement totales doivent être équipées d\'une infrastructure de recharge VE active — Stationnement collectif :\n(minimum 7 kW). Toutes les places de stationnement restantes doivent disposer d\'une infrastructure de recharge VE passive.","2"]]},{"title": "Tableau 60 : Emplacements vélos par logement et points disponibles","after_section": "M2","headers": ["Taille du logement","Points disponibles, selon le nombre d\'emplacements vélos fournis","","",""],"rows": [["","1 emplacement vélo\npour 2 logements","1 emplacement vélo\npar logement","2 emplacements vélos\npar logement","4 emplacements vélos\npar logement"],["Studio ou une\nchambre","1 point","2 points","2 points","2 points"],["2 à 3 chambres","0","1 point","2 points","2 points"],["4 chambres ou plus","0","0","1 point","2 points"]]},{"title": "Tableau 61 : Types d\'équipements de proximité pour bâtiments résidentiels (Options 8 et 9)","after_section": "M4","headers": ["Équipements de proximité applicables au résidentiel","",""],"rows": [["Équipements de proximité applicables au résidentiel","",""],["Option","A","B"],["Nombre d\'équipements requis","4","7"],["Proximité (mètres)","500","1000"],["Point de restauration adapté","C","C"],["Accès à un distributeur automatique de billets (DAB)","C","C"],["Accès à un espace extérieur ouvert (public ou privé, de taille adaptée et\naccessible aux usagers du bâtiment)","C","C"],["Accès à une installation de loisirs ou de sport","✔","✔"],["Bureau de poste accessible au public","✔","✔"],["Équipement collectif / salle communale","✔","✔"],["Pharmacie","✔","✔"],["Cabinet médical ou centre de santé","✔","✔"],["Structure d\'accueil pour enfants ou école","✔","✔"]]}],"Wat01": [{"title": "Tableau 63 : Données requises pour chaque type de composant consommateur d\'eau","after_section": "M2.1","headers": ["Composant consommateur d\'eau","Données requises"],"rows": [["WC/toilettes","Volume de chasse complète et, le cas échéant, volume de chasse réduite en litres par utilisation"],["Urinoir","Volume de chasse en litres/cuvette/heure"],["Robinets de lavabo","Débit maximal en litres par minute, y compris toute réduction obtenue par des limiteurs de débit [note 1]"],["Douche","Débit maximal en litres par minute, y compris toute réduction obtenue par des limiteurs de débit"],["Robinet de cuisine","Débit maximal en litres par minute, y compris toute réduction obtenue par des limiteurs de débit"],["Baignoire","Capacité jusqu\'au trop-plein en litres [note 2]"],["Lave-vaisselle – taille domestique","litres/cycle"],["Lave-vaisselle – taille professionnelle","litres/casier"],["Lave-linge – taille domestique","litres/utilisation (basé sur un cycle de lavage type)"],["Lave-linge – taille professionnelle","litres/kg"],["Broyeur de déchets","Débit en litres par minute"],["Notes\n1. Le débit d\'un robinet ou d\'une douche varie en fonction de la pression d\'eau : — Pour les systèmes d\'alimentation haute pression, les mesures d\'essai doivent être effectuées à 3 ± 0,02 bar (0,3 ± 0,02 MPa). — Pour les systèmes d\'alimentation basse pression, les mesures d\'essai doivent être effectuées à 0,1 ± 0,02 bar (0,01 ± 0,002 MPa).\n2. Le calcul de la consommation d\'eau des baignoires suppose 40 % de la capacité jusqu\'au trop-plein. Cela reflète le fait que : — Les utilisateurs ne remplissent généralement pas la baignoire jusqu\'au trop-plein. — L\'effet de déplacement de l\'utilisateur sur le volume réel d\'eau nécessaire pour un bain.",""]]},{"title": "Tableau 64 : Niveaux de performance de référence pour les composants consommateurs d\'eau","after_section": "M3","headers": ["Composant consommateur d\'eau","Niveau de performance de référence"],"rows": [["WC/toilettes","6,0 litres – volume de chasse effectif"],["Urinoir","8,75 litres/cuvette/heure"],["Robinets de lavabo","10 litres/minute"],["Douche","12 litres/minute"],["Robinet de cuisine","10 litres/minute"],["Baignoire","200 litres"],["Lave-vaisselle – taille domestique","17 litres/cycle"],["Lave-vaisselle – taille professionnelle","8 litres/casier"],["Lave-linge – taille domestique","90 litres/utilisation"],["Lave-linge – taille professionnelle","14 litres/kg"],["Broyeur de déchets","17 litres/minute"]]}],"Wat04": [{"title": "Tableau 67 : Exigences réputées conformes pour les systèmes consommateurs d\'eau non sanitaires","after_section": "M4.2","headers": ["Type de système ou\nd\'équipement","Exigences"],"rows": [["Piscines","Des couvertures de piscine automatiques ou semi-automatiques, ou des couvertures « liquides » avec un système de dosage\nautomatique, sont installées sur toute la surface du bassin.\nET\nPour les piscines intérieures : La température de l\'air dans le hall de piscine peut être régulée pour être supérieure de 1°C\nà la température de l\'eau.\nOU\nPour les piscines extérieures : Des brise-vent tels que clôtures, rochers ou haies sont utilisés pour réduire\nl\'évaporation."],["Jacuzzis et bassins\nde balnéothérapie","Des couvertures automatiques ou semi-automatiques, ou des couvertures « liquides » avec un système de dosage\nautomatique, sont installées sur toute la surface du bassin."],["Plantations et aménagements paysagers","L\'arrosage est assuré par un système d\'irrigation contrôlé utilisant des données météorologiques locales ou des\nsondes d\'humidité du sol.\nOU\nDe l\'eau récupérée provenant d\'un système de collecte des eaux pluviales ou de récupération des eaux usées\navec un stockage adapté, c\'est-à-dire la collecte des eaux grises issues des fonctions ou processus du bâtiment utilisant\nde l\'eau potable (ex. lavage de véhicules, installations sanitaires, irrigation, etc.) est utilisée de préférence à\nd\'autres sources d\'eau.\nOU\nAménagements paysagers et plantations extérieurs ne dépendant que des précipitations, en toutes saisons,\nune fois les plantations établies (voir NC1)."],["Éléments aquatiques tels que\nles fontaines décoratives","Arrêt automatique en dehors des heures d\'occupation.\nOU\nDes brise-vent tels que clôtures, rochers ou haies sont utilisés pour réduire l\'évaporation."],["Stations de lavage de véhicules","Équipées d\'un système de recyclage de l\'eau.\nOU\nUtilisent de l\'eau de pluie ou des eaux usées."],["Tours de refroidissement","Contrôle automatique de purge régulant les moments de décharge.\nOU\nÉquipées d\'un brise-vent, de couvertures flottantes ou d\'autres types de protection."],["Systèmes utilisant l\'eau pour\nle refroidissement ou le chauffage","Utilise un système de circulation d\'eau en boucle fermée."]]}],"Mat01": [{"title": "Tableau 69 : Exigences de qualité de l\'ACV","after_section": "M3","headers": ["Exigence de qualité","Stade de conception\npréliminaire","Stade de conception\ntechnique","Stade post-construction"],"rows": [["1. Quantités de\nconstruction\nélémentaires","Estimations basées sur des\nréférences élémentaires ou des\ndocuments de conception au\nstade de conception préliminaire.","Quantités calculées présentées dans les\ndocuments de conception au stade de\nconception technique.","Quantités réalisées."],["2. Type de données\nACV ou DEP","Données génériques ou spécifiques\nau fabricant si spécifié.","Par ordre de préférence, la sélection\ndoit se faire ainsi :\n1. DEP produit du fabricant\ndu produit spécifique que vous\nprévoyez d\'utiliser, si disponible.\n2. Données génériques.","Par ordre de préférence, la\nsélection doit se faire\nainsi :\n1. DEP produit du\nfabricant du produit\nspécifique utilisé,\nsi disponible."]]}],"Mat02": [{"title": "Tableau 70 : Points DEP selon le type de DEP","after_section": "M1","headers": ["Types de DEP reconnus","Validité","Points\nDEP"],"rows": [["DEP applicable à plus d\'un produit de la\nmême catégorie de produits et à plus d\'un\nfabricant.","— DEP non expirée au moment de la spécification.\n— Produit installé dans le bâtiment avant la fin de\nla construction.\n— DEP émise ou enregistrée par un opérateur de\nprogramme conforme à l\'ISO 14025.\n— Pour les produits couverts par le Règlement sur les\nProduits de Construction, la DEP doit avoir été générée\nen utilisant des règles de catégorie de produits basées\nsur la BS EN 15804.","0.5"],["DEP applicable à plus d\'un produit de la\nmême catégorie de produits et à un seul\nfabricant.","","0.75"],["DEP applicable à un seul produit*, et un seul\nfabricant (le produit peut être\nfabriqué sur plusieurs sites)\n*Ou des variantes d\'un même produit ne différant\nque par la couleur ou le motif.","","1.5"]]},{"title": "Tableau 71 : Classification des matériaux","after_section": "M1","headers": ["Réf","Catégorie de matériau","Codes Uniclass 1.4 (à titre indicatif)"],"rows": [["Réf","Catégorie de matériau","Codes Uniclass 1.4 (à titre indicatif)"],["1","Bois ou produits à base de bois","P5"],["2","Béton ou cimentaire","P2*"],["3","Métal","P4"],["4","Pierre ou granulat","P1, P3*"],["5","À base d\'argile","P33"],["6","Plâtre","P232"],["7","Verre","P314"],["8","Plastique, polymère, résine, peinture, produits chimiques et bitumineux","P7, P34"],["9","Fibre animale ou peau, fibre cellulosique","P6"],["10","Autre","P8"],["*À l\'exception des sous-ensembles énumérés séparément. Par exemple, P2 se rapporte généralement à « Béton ou matériau cimentaire » sauf pour le sous-ensemble P232 qui se rapporte à « Gypse ».","",""]]}],"Mat03": [{"title": "Tableau 73 : Mat 03 – Périmètre pour la superstructure","after_section": "M2","headers": ["Périmètre (basé sur le système de classification NRM)","",""],"rows": [["2 Superstructure","2.1 Ossature","2.1.1 Ossatures acier"],["","","2.1.2 Planchers-dalles"],["","","2.1.3 Enrobages béton des ossatures acier"],["","","2.1.4 Ossatures béton"],["","","2.1.5 Ossatures bois"],["","","2.1.6 Autres systèmes d\'ossature"],["","2.2 Planchers hauts","2.2.1 Planchers"],["","2.3 Toiture","2.3.1 Structure de toiture"],["","","2.3.2 Couverture de toiture"],["","","2.3.3 Systèmes de toiture spécialisés"],["","","2.3.5 Lanterneaux, verrières et ouvertures"],["","2.4 Escaliers et rampes","2.4.1 Structures d\'escaliers ou de rampes"],["","2.5 Murs extérieurs","2.5.1 Murs de façade au-dessus du niveau du rez-de-chaussée"],["","","2.5.2 Murs de façade en dessous du niveau du sol"],["","","2.5.3 Protection solaire ou pare-pluie"],["","2.6 Fenêtres et portes extérieures","2.6.1 Fenêtres – verticales"],["","","2.6.2 Fenêtres – toiture ou horizontales"],["","","2.6.3 Portes extérieures"],["","2.7 Murs intérieurs et cloisons","2.7.1 Murs et cloisons"]]},{"title": "Tableau 74 : Mat 03 – Périmètre pour les finitions intérieures","after_section": "M2","headers": ["Périmètre (basé sur le système de classification NRM)","",""],"rows": [["2 Superstructure","2.4 Escaliers et rampes","2.4.2 Finitions d\'escaliers ou de rampes"],["","2.8 Portes intérieures","2.8.1 Portes intérieures"],["3 Finitions intérieures","3.1 Finitions murales","3.1.1 Finitions des murs"],["","3.2 Finitions de sol","3.2.1 Finitions des sols"],["","","3.2.2 Planchers surélevés"],["","3.3 Finitions de plafond","3.3.1 Finitions des plafonds"],["","","3.3.2 Faux plafonds"],["","","3.3.3 Plafonds suspendus démontables"]]},{"title": "Tableau 75 : Mat 03 – Périmètre pour l\'infrastructure et les aménagements extérieurs en dur","after_section": "M2","headers": ["Périmètre (basé sur le système de classification NRM)","",""],"rows": [["1 Infrastructure","1.1 Infrastructure","1.1.1 Fondations standard"],["","","1.1.2 Systèmes de fondation spécialisés"],["","","1.1.3 Construction du plancher bas"],["","","1.1.4 Excavation de sous-sol"],["","","1.1.5 Murs de soutènement de sous-sol"],["8 Aménagements extérieurs*","8.2 Routes, chemins et dallages","8.2.1 Routes, chemins et dallages"],["","","8.2.2 Revêtements et dallages spéciaux"],["*Inclure les aménagements extérieurs en dur installés dans le cadre du projet évalué et : — Situés dans l\'enceinte définie du bâtiment. — Ou clairement associés à celui-ci (par exemple, une voie d\'accès ou un parking destiné à desservir uniquement le bâtiment évalué ou le bâtiment et, dans une moindre mesure, d\'autres bâtiments).\n\nLes aménagements extérieurs en dur sans distinction de ce type sont exclus.","",""]]},{"title": "Tableau 76 : Mat 03 – Périmètre pour les équipements techniques principaux","after_section": "M2","headers": ["Périmètre (basé sur le système de classification NRM)","",""],"rows": [["5 Équipements techniques","5.5 Source de chaleur","5.5.1 Source de chaleur"],["","5.6 Chauffage et climatisation","5.6.1 Chauffage central"],["","","5.6.2 Chauffage local"],["","","5.6.3 Refroidissement central"],["","","5.6.4 Refroidissement local"],["","","5.6.5 Chauffage et refroidissement centraux"],["","","5.6.6 Chauffage et refroidissement locaux"],["","","5.6.7 Climatisation centrale"],["","","5.6.8 Climatisation locale"],["","5.7 Ventilation","5.7.1 Ventilation centrale"],["","","5.7.2 Ventilation locale"],["","","5.7.3 Désenfumage ou contrôle des fumées"],["","5.9 Installations et systèmes de combustible","5.9.1 Stockage de combustible"],["","","5.9.2 Systèmes de distribution de combustible"]]},{"title": "Tableau 77 : Catégories de localisation BREEAM","after_section": "M2","headers": ["Classification NRM","Catégorie de localisation BREEAM"],"rows": [["1.1 Infrastructure","Structure primaire et secondaire"],["2.1 Ossature","Structure primaire et secondaire"],["2.2 Planchers hauts","Plancher (y compris finitions de sol)"],["2.3 Toiture","Toiture (y compris finitions de toiture)"],["2.4 Escaliers et rampes","Structure primaire et secondaire"],["2.5 Murs extérieurs","Mur extérieur (y compris finitions, ex. bardage, doublage, enduit)"],["2.6 Fenêtres et portes extérieures","Porte ou fenêtre"],["2.7 Murs intérieurs et cloisons","Cloison intérieure ou murs intérieurs (y compris finitions)"],["2.8 Portes intérieures","Porte ou fenêtre"],["3.1 Finitions murales","Cloison intérieure ou murs intérieurs (y compris finitions)"],["3.2 Finitions de sol","Plancher (y compris finitions de sol)"],["3.3 Finitions de plafond","Plafond (y compris finitions de plafond)"],["5.5.1 Source de chaleur","Équipements techniques"],["5.6 Chauffage et climatisation","Équipements techniques"],["5.7 Ventilation","Équipements techniques"],["5.9 Installations ou systèmes de combustible","Équipements techniques"],["8.2 Routes, chemins et dallages","Aménagements extérieurs en dur"]]},{"title": "Tableau 78 : Catégories de matériaux","after_section": "M3","headers": ["Réf","Catégorie de matériau"],"rows": [["1","Bois ou produits à base de bois"],["2","Béton ou cimentaire"],["3","Métal"],["4","Pierre ou granulat"],["5","À base d\'argile"],["6","Plâtre"],["7","Verre"],["8","Plastique, polymère, résine, peinture, produits chimiques et bitumineux"],["9","Fibre animale ou peau, fibre cellulosique"],["10","Autre"]]},{"title": "Tableau 79 : Seuils d\'exclusion pour les produits et matériaux dans Mat 03","after_section": "M6","headers": ["Catégorie de localisation","Seuil d\'exclusion"],"rows": [["Cloison intérieure ou murs intérieurs (y compris finitions)","Tout produit inférieur à 0,33 m³ pour 1000 m² de surface utile brute (SUB)"],["Plafond (y compris finitions de plafond)","Tout produit inférieur à 0,33 m³ pour 1000 m² de SUB"],["Toutes les autres catégories de localisation","Tout produit inférieur à 1 m³ pour 1000 m² de SUB"]]}],"Mat04": [{"title": "Tableau 80 : Éléments de construction, facteurs environnementaux et effets de dégradation applicables","after_section": "M3","headers": ["Éléments de construction, facteurs environnementaux et effets de dégradation applicables"],"rows": [["Éléments de construction, facteurs environnementaux et effets de dégradation des matériaux applicables"],["Éléments de construction applicables"],["1. Fondations, infrastructure, plancher bas, murs de soutènement\n2. Murs extérieurs\n3. Toiture ou balcons\n4. Vitrages : fenêtres, lanterneaux\n5. Portes extérieures\n6. Garde-corps ou balustrades (exposés à l\'environnement extérieur)\n7. Bardage (exposé à l\'environnement extérieur)\n8. Escaliers ou rampes (exposés à l\'environnement extérieur)\n9. Aménagements extérieurs en dur."],["Facteurs environnementaux"],["1. Agents environnementaux, notamment :\na. Rayonnement solaire\nb. Variations de température\nc. Eau ou humidité\nd. Vent\ne. Précipitations, ex. pluie et neige\nf. Conditions météorologiques extrêmes : vents violents, inondations, pluie battante, neige\n2. Agents biologiques, notamment :\na. Végétation\nb. Nuisibles, insectes\n3. Polluants, notamment :\na. Contaminants atmosphériques\nb. Contaminants du sol."],["Effets de dégradation des matériaux (incluant, sans s\'y limiter, les éléments suivants)"],["1. Corrosion\n2. Variation dimensionnelle, ex. gonflement ou retrait\n3. Décoloration ou altération de la couleur\n4. Pourrissement\n5. Lixiviation\n6. Cloquage\n7. Fusion\n8. Cristallisation de sels\n9. Abrasion."]]}],"Mat05": [{"title": "Tableau 81 : Stratégie d\'efficacité des matériaux","after_section": "M1","headers": ["Phases de projet et efficacités",""],"rows": [["Préparation et Programme",""],["Objectif","Définir les exigences qui guideront les décisions tout au long de la conception et de la construction\ndu projet."],["Participants","Maître d\'ouvrage ou mandataire du maître d\'ouvrage avec contribution de l\'équipe de conception si désignée."],["Action","Évaluer le site, l\'envergure probable du projet et les exigences fonctionnelles et esthétiques du maître d\'ouvrage\npour définir les objectifs d\'efficacité des matériaux du projet."],["Justificatif","Rapport dédié établissant un cadre clair pour guider les activités d\'efficacité des matériaux\ntout au long de la conception et de la construction du projet. Le rapport doit définir les buts,\nobjectifs, cibles, indicateurs de performance, opportunités, contraintes et responsabilités pour\nguider les activités d\'efficacité des matériaux."],["Conception Préliminaire",""],["Objectif","Développer des stratégies pour mettre en œuvre les exigences d\'efficacité des matériaux définies lors\nde la phase de Préparation et Programme."],["Participants","Équipe de conception comprenant au minimum :\n— Architecte\n— Ingénieur structure\n— Ingénieur fluides et CVC"],["Action","Organiser des ateliers avec l\'équipe de projet pour identifier les opportunités de conception permettant de réduire ou d\'optimiser\nl\'utilisation des matériaux par la conception, les spécifications, les techniques de construction, etc."],["Justificatif","Comptes-rendus des ateliers réalisés. Documentation démontrant comment les retours des ateliers\nont été intégrés dans la conception préliminaire du projet, par exemple : spécifications générales\npour la sélection des matériaux, rapport sur les réductions approximatives prévues des quantités de matériaux."],["Conception Détaillée et Conception Technique",""],["Objectif","Développer les propositions de conception sur la base des enseignements de la conception préliminaire."],["Participants","Tous les membres pertinents de l\'équipe de conception."],["Action","Intégrer les mesures et stratégies d\'efficacité des matériaux identifiées en conception préliminaire dans\nla conception architecturale, structurelle et des équipements techniques selon le cas. Évaluer la performance\npar rapport aux phases précédentes et identifier les écarts."],["Justificatif","Rapport sur les écarts par rapport aux phases précédentes et les actions complémentaires à entreprendre.\nDocumentation démontrant l\'intégration des résultats de la phase de conception préliminaire\net des actions complémentaires, par exemple : plans ou spécifications démontrant\nles mesures d\'efficacité des matériaux mises en œuvre."],["Construction",""],["Objectif","Mettre en œuvre les mesures d\'efficacité des matériaux en phase de construction."],["Participants","Entreprise principale."],["Action","Mettre en œuvre les mesures et stratégies d\'efficacité des matériaux identifiées lors des phases précédentes\ndans la construction du bâtiment et identifier les écarts. Identifier d\'autres gains d\'efficacité appropriés\npour cette phase."],["Justificatif","Rapport sur les écarts par rapport aux phases précédentes. Preuves documentées des activités visant à identifier\nd\'autres gains d\'efficacité à ce stade, par exemple : comptes-rendus de réunions, sessions de formation, documentation\nde réduction des déchets, etc."]]}],"Lue04": [{"title": "Tableau 92 : Types de surfaces et facteurs de pondération par m²","after_section": "M3.8","headers": ["Type de surface","Description","Facteurs de\npondération\npar m² / ft²"],"rows": [["Surfaces imperméables","Surface imperméable à l\'air et à l\'eau, sans végétation (ex. béton,\nenrobé, dalles sur assise rigide).","0.0"],["Surfaces partiellement\nimperméables","Surface perméable à l\'eau et à l\'air ; en règle générale, pas de végétation (ex. pavés clinker,\ndallage mosaïque, dalles sur assise sable ou gravier).","0.1"],["Surfaces semi-ouvertes","Surface perméable à l\'eau et à l\'air, infiltration d\'eau, mais pas de végétation planifiée\n(ex. sable, gravier, pavés clinker à forte infiltration d\'eau).","0.2"],["Surfaces végétalisées","Surface perméable à l\'eau et à l\'air, infiltration d\'eau et végétation planifiée à long terme\n(ex. gravier engazonné, pavés en bois, dalles gazon).","0.4"],["Surfaces végétalisées sur\ncouche de sol rapportée,\nfaible épaisseur\nde substrat","Surfaces végétalisées non connectées au sol naturel sous-jacent avec une couche de sol de 20 à\n40 cm d\'épaisseur, ex. jardinières, couche de sol avec pelouse, petits arbustes et vivaces.","0.5"],["Surfaces végétalisées sur\ncouche de sol rapportée,\népaisseur moyenne\nde substrat","Surfaces végétalisées non connectées au sol naturel sous-jacent avec une couche de sol de 41 à\n80 cm d\'épaisseur, ex. couche de sol avec haies et grands arbustes.","0.6"],["Surfaces végétalisées sur\ncouche de sol rapportée,\nforte épaisseur\nde substrat","Surfaces végétalisées non connectées au sol naturel sous-jacent avec une couche de sol de 81 à 150\ncm d\'épaisseur, ex. couche de sol avec arbres moyens et grands.","0.7"],["Surfaces végétalisées sur\ncouche de sol rapportée,\ntrès forte épaisseur\nde substrat","Surfaces végétalisées non connectées au sol naturel sous-jacent avec une couche de sol\nd\'une épaisseur supérieure à 150 cm, ex. couche de sol avec de très grands arbres.","0.9"],["Surface végétalisée\nconnectée au\nsol naturel","Surface végétalisée à forte densité de couverture ; surface totalement perméable à l\'air et à l\'eau\navec connexion au sol naturel. Si seuls de faibles volumes de végétation peu structurée sont\nétablis (ex. pelouses ornementales), le facteur de pondération est réduit à 0,5.","1.0"],["Surfaces de gestion\ndurable des eaux\npluviales (SUDS)","Surfaces gérant le ruissellement des eaux de pluie par infiltration et collecte,\nex. noues, surfaces d\'infiltration. La surface totale est mesurée, quelle que soit\nl\'orientation. Pas de dispositifs d\'infiltration exclusivement souterrains.","0.2"],["Plan d\'eau","Plan d\'eau alimenté par les eaux de pluie, ex. bassins pluviaux, lacs artificiels, tourbières artificielles,\nzones humides artificielles.","0.5"],["Plan d\'eau avec\nvégétation","Identique à ci-dessus, avec en plus de la végétation dans ou autour du plan d\'eau.","0.6"],["Végétalisation verticale\navec connexion\nau sol","Connexion directe de la végétalisation verticale avec le sol. La végétation est alimentée en\nnutriments et en eau directement par les racines dans le sol. La surface totale est\nmesurée, quelle que soit l\'orientation.","0.5"],["Végétalisation verticale\nsans connexion\nau sol","Végétation verticale ou horizontale sur un mur sans connexion directe avec le sol,\nex. jardinières permanentes avec irrigation artificielle.","0.7"],["Toiture végétalisée\nextensive","Aménagement naturel des surfaces de toiture avec une épaisseur de substrat inférieure à 20 cm\nsans irrigation artificielle. Si des systèmes de rétention d\'eau sont présents, le FBU peut\naugmenter à 0,6 (uniquement pour les toitures végétalisées extensives).","0.5"],["Toiture végétalisée\nsemi-intensive","Combinaison de végétalisation extensive et intensive avec une épaisseur de substrat de 15 à\n50 cm (selon les plantations choisies), généralement avec irrigation artificielle,\nex. toitures végétalisées avec herbes aromatiques, graminées, vivaces et petits arbustes.","0.7"],["Toiture végétalisée intensive","Aménagement de la toiture similaire aux espaces verts au sol avec une épaisseur de substrat supérieure à 50 cm, généralement avec irrigation artificielle, ex. toitures végétalisées avec\nvivaces moyennes à hautes et arbustes.","0.8"]]}],"Pol01": [{"title": "Tableau 94 : Fluides frigorigènes avec un PRG inférieur à 10 kgCO₂e/kg","after_section": "M3.1","headers": ["Fluide frigorigène","PRG, kgCO₂e/kg"],"rows": [["R600 = butane","0.006"],["R290 = propane","0.06"],["R433B","0.16"],["R441A","0.23"],["R170 = éthane","0.437"],["R433C","0.55"],["R433A","0.64"],["Dioxyde de carbone","1"],["R443A","1"],["Diméthyléther","1"],["R1234yf*","1"],["R1234ze*","1"],["R510A","1.24"],["R436A","1.35"],["R436B","1.47"],["R432A","1.8"],["Bromure de méthyle","2"],["R1270 = propène","2"],["R600A = isobutane","3"],["HFC-161","4"],["R601 = pentane","5"],["R601A = isopentane","5"],["R511A","7"],["Chlorure de méthylène","9"],["* Aucune valeur spécifique n\'est disponible, mais il est établi que le facteur PRG est < 1 kgCO₂e/kg",""]]}],"Pol04": [{"title": "Tableau 96 : Zone d\'éclairage environnemental","after_section": "M4","headers": ["Zone","Classification","Luminosité","Description"],"rows": [["E0","Protégé","Sombre","Ciels étoilés observables astronomiquement,\nréserves de ciel étoilé UNESCO, sites IDA de\nciel étoilé"],["E1","Naturel","Sombre","Parcs nationaux ou sites protégés, zones de\nbeauté naturelle exceptionnelle, zones rurales\nrelativement inhabitées"],["E2","Rural","Faible luminosité de zone","Zones rurales peu peuplées, villages ou\nlocalités périurbaines relativement sombres"],["E3","Périurbain","Luminosité de zone moyenne","Zones rurales et urbaines bien habitées,\ncentres de petites villes ou zones périurbaines"],["E4","Urbain","Forte luminosité de zone","Centres-villes et quartiers commerciaux avec\nniveaux élevés d\'activité nocturne"]]},{"title": "Tableau 97 : Valeurs maximales autorisées de luminance nocturne des affichages (cd/m²)","after_section": "M4","headers": ["Surface de l\'affichage (m²)","E0","E1","E2","E3","E4"],"rows": [["0 à < 5","0","25","200","300","300"],["5 à < 20","0","0","200","300","300"],["≥ 20","0","0","100","200","300"]]}]};
